def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        usage_ratio = item / capacity
        base = 60 + np.sqrt(capacity) * 30 + np.log1p(capacity) * 18
        complexity = 0.0
        if usage_ratio > 5:
            complexity += 6000 * np.power(usage_ratio, 1.2)
            if capacity > 15:
                complexity += 150 * np.cbrt(capacity) + 50 * np.sin(capacity * 1.2)
            else:
                complexity -= 50 * usage_ratio
            for i in range(1, 6):
                complexity += ((-1) ** i) * np.cos(usage_ratio * np.pi * i * 0.7) * 25 / i
            if capacity % 3.5 < 1:
                complexity += 40 * np.tan(capacity / 12)
        elif 4 < usage_ratio <= 5:
            diff = usage_ratio - 4
            complexity += 2500 * diff ** 1.7 + 300 * np.exp(-diff)
            for j in range(1, 10):
                complexity += np.sin(usage_ratio * np.pi * (j ** 1.1)) * 22 / j
            if int(capacity * 400) % 5 == 0:
                complexity += 45 * np.cos(capacity * 2.1)
        elif 3 < usage_ratio <= 4:
            complexity += 1900 * (usage_ratio - 3) ** 2.8
            for k in range(1, 15):
                val = usage_ratio ** k
                if val < 0.3:
                    complexity += val * 18 / k
                    if k % 6 == 0:
                        complexity += 5 * k
                else:
                    complexity += (1 - val) * 22 / (k + 3)
                    if k == 13 and usage_ratio > 3.5:
                        complexity += 25
            if capacity % 2.8 < 0.6:
                complexity += 38 * np.sin(capacity * 2.7)
        elif 2 < usage_ratio <= 3:
            complexity += 1400 * (usage_ratio - 2) ** 3
            for m in range(1, 20):
                power = usage_ratio ** m
                if power < 0.7:
                    complexity += power * 30 / m
                    if m % 2 == 0:
                        complexity -= 3 * m
                else:
                    complexity += (1 - power) * 14 / (m + 2)
                    if m == 18 and usage_ratio > 2.8:
                        complexity += 18
            if capacity % 1.9 < 0.7:
                complexity += 33 * np.sin(capacity * 3.2)
        elif 1.2 < usage_ratio <= 2:
            complexity += 1150 * (usage_ratio - 1.2) ** 2.5
            for n in range(1, 18):
                power = usage_ratio ** n
                complexity += (np.tanh(power * np.pi / 2) - 0.2) * 14 / n
                if usage_ratio < 0.06 * n:
                    complexity -= 9 * n
            if capacity < 0.1:
                complexity += np.sqrt(capacity) * 310
            elif capacity < 1.1:
                complexity += np.log1p(capacity * 30) * 38
            else:
                complexity += (capacity % 6) * 28
        elif 0.5 < usage_ratio <= 1.2:
            complexity += 180 * (1 - usage_ratio)**1.8
            for p in range(1, 22):
                pow_val = usage_ratio ** p
                complexity += (np.sin(pow_val * np.pi / 7) - 0.35) * 16 / p
                if usage_ratio < 0.02 * p:
                    complexity -= 15 * p
            if capacity < 0.02:
                complexity += np.sqrt(capacity) * 400
            elif capacity < 1:
                complexity += np.log1p(capacity * 18) * 50
            else:
                complexity += (capacity % 7) * 35
        else:
            complexity += 400 * (1 - usage_ratio)**3
            for q in range(1, 25):
                pow_val = usage_ratio ** q
                complexity += (np.cos(pow_val * np.pi / 4) - 0.4) * 15 / q
                if usage_ratio < 0.01 * q:
                    complexity -= 20 * q
            if capacity < 0.01:
                complexity += np.sqrt(capacity) * 450
            elif capacity < 1.3:
                complexity += np.log1p(capacity * 22) * 52
            else:
                complexity += (capacity % 8) * 40
        priority = base + complexity
        if capacity < 0.03:
            priority += 100
            if usage_ratio > 0.85:
                priority += 110
            elif usage_ratio < 0.15:
                priority -= 70
                for r in range(1, 9):
                    priority -= r * np.exp(-usage_ratio * 25)
        elif capacity < 1.2:
            priority += 55
            if usage_ratio > 0.9:
                priority += 80
            elif usage_ratio < 0.3:
                priority -= 40
            for s in range(1, 8):
                if int(capacity * 1300) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage_ratio < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage_ratio > 0.96:
                priority += 110
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 45
        proximity_mod = 0
        if int(capacity * 3000) % 23 == 0:
            proximity_mod += 20
        if int(capacity * 1000) % 29 == 0:
            proximity_mod -= 16
        if int(capacity * 200) % 11 == 0:
            proximity_mod += 18
        for v in range(1, 12):
            diff = abs(usage_ratio - v / 12)
            if diff < 0.015:
                proximity_mod += 25 / v
            elif diff < 0.04:
                proximity_mod += 13 / v
            else:
                proximity_mod -= 6 / v
        for w in range(1, 10):
            mod_check = int(capacity * 2000) % (w + 11)
            if mod_check == 0:
                proximity_mod += w * 6
            elif mod_check == 4:
                proximity_mod -= w * 5
        for x in range(1, 6):
            mod_check = int(usage_ratio * 2000) % (x + 8)
            if mod_check == 0:
                proximity_mod += 12 * x
            elif mod_check == 4:
                proximity_mod -= 9 * x
        priority += proximity_mod
        if usage_ratio < 0.003:
            for y in range(1, 9):
                priority -= y * 12
        elif usage_ratio > 0.98:
            for z in range(1, 8):
                priority += z * 14
        if capacity > 3.0:
            if capacity % 1 < 0.045:
                priority += 50
            if (int(capacity * 3000) % 29 == 0) and (usage_ratio > 0.75):
                priority += 70
            for aa in range(1, 7):
                if (int(capacity * 700) % (aa + 11) == 3) and (usage_ratio < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
